const data = $json.body || $json;
const errors = [];

if (!data.name) errors.push("الاسم مفقود");
if (!data.description) errors.push("الوصف مفقود");

// Check if images array exists and has at least one image
if (!data.images || !Array.isArray(data.images) || data.images.length === 0) {
  errors.push("الصورة الأولى مفقودة");
}

if (data.price === undefined || data.price === null) {
  errors.push("السعر مفقود");
} else if (isNaN(Number(data.price))) {
  errors.push("السعر يجب أن يكون رقم");
}

if (errors.length > 0) {
  throw new Error(errors.join(", "));
}

// Process multiple images from array
const images = [];
const timestamp = Date.now();

data.images.forEach((image, index) => {
  if (image.base64) {
    const base64Data = image.base64.includes(',') ? image.base64.split(',')[1] : image.base64;
    const imageBuffer = Buffer.from(base64Data, 'base64');
    const fileName = `products/${timestamp}_image_${index + 1}_${image.name || `image${index + 1}.jpg`}`;
    const mimeType = image.base64.includes(';') ? image.base64.split(';')[0].split(':')[1] : 'image/jpeg';

    images.push({
      index: index + 1,
      buffer: imageBuffer,
      fileName: fileName,
      mimeType: mimeType
    });
  }
});

if (images.length === 0) {
  throw new Error("يجب توفير صورة واحدة على الأقل");
}

return [{
  json: {
    name: data.name,
    description: data.description,
    price: Number(data.price),
    user_id: data.user_id || 1,
    text: `${data.name} - ${data.description}`,
    images: images,
    totalImages: images.length
  }
}];

const bucketName = 'te-kamul-products-eu-central-1-1248';
const region = 'eu-central-1';

// محاولة الحصول على الاسم من مخرجات S3، وإذا فشل نجلبه من النود السابق Loop Images
const fileName = $json.Key || $('Loop Images').item.json.fileName;

if (!fileName) {
  throw new Error('⚠️ لم يتم العثور على fileName في البيانات المُدخلة أو النود السابق');
}

const s3Url = `https://${bucketName}.s3.${region}.amazonaws.com/${fileName}`;

return {
  json: {
    imageIndex: $('Loop Images').item.json.imageIndex, // استرجاع الفهرس من النود الأصلي
    image_url: s3Url,
    fileName: fileName,
    name: $('Loop Images').item.json.name,
    description: $('Loop Images').item.json.description,
    price: $('Loop Images').item.json.price,
    user_id: $('Loop Images').item.json.user_id
  }
};

