<div class="modal-box">

<h3 id="title">إضافة منتج</h3>
<input type="hidden" id="pid">

<div class="form-group">
<input id="name" placeholder="اسم المنتج">
</div>

<div class="form-group">
<textarea id="desc" placeholder="الوصف"></textarea>
</div>

<div class="form-group">
<input id="price" type="number" placeholder="السعر">
</div>

<div class="form-group">
<div class="upload-box" onclick="document.getElementById('images').click()">
<i class="fa fa-cloud-upload"></i> رفع صور
</div>
<input type="file" id="images" multiple accept="image/*" hidden>
<div class="preview" id="preview"></div>
</div>

<button class="save-btn" onclick="save()">💾 حفظ</button>
<button class="cancel-btn" onclick="closeModal()">❌ إلغاء</button>

</div>
</div>

<script>

let selectedImages=[];

function openModal(){
 document.getElementById("modal").classList.add("show");
 reset();
}

function closeModal(){
 document.getElementById("modal").classList.remove("show");
}

function reset(){
 document.getElementById("pid").value="";
 document.getElementById("name").value="";
 document.getElementById("desc").value="";
 document.getElementById("price").value="";
 document.getElementById("preview").innerHTML="";
 selectedImages=[];
}

document.getElementById("images").addEventListener("change",function(){
 selectedImages=[...this.files];
 const preview=document.getElementById("preview");
 preview.innerHTML="";
 selectedImages.forEach(file=>{
  const r=new FileReader();
  r.onload=e=>{
   const img=document.createElement("img");
   img.src=e.target.result;
   preview.appendChild(img);
  }
  r.readAsDataURL(file);
 });
});

function editProduct(id,name,desc,price){
 openModal();
 document.getElementById("title").innerText="تعديل منتج";
 document.getElementById("pid").value=id;
 document.getElementById("name").value=name;
 document.getElementById("desc").value=desc;
 document.getElementById("price").value=price;
}

async function save(){
 const id=document.getElementById("pid").value;
 const name=document.getElementById("name").value;
 const desc=document.getElementById("desc").value;
 const price=document.getElementById("price").value;

 let imagesData={};

 for(let i=0;i<selectedImages.length;i++){
  const b64=await toBase64(selectedImages[i]);
  imagesData["image_base64_"+(i+1)]=b64;
 }

 let url=id
 ? "https://n8n-n8n.17m6co.easypanel.host/webhook/update-product"
 : "https://n8n-n8n.17m6co.easypanel.host/webhook/add-product";

 let payload={name,description:desc,price:Number(price),...imagesData};
 if(id) payload.product_id=id;

 await fetch(url,{
  method:"POST",
  headers:{"Content-Type":"application/json"},
  body:JSON.stringify(payload)
 });

 alert("تم الحفظ");
 location.reload();
}

function deleteProduct(id){
 if(!confirm("تأكيد الحذف؟")) return;

 fetch("https://n8n-n8n.17m6co.easypanel.host/webhook/delete-product",{
  method:"POST",
  headers:{"Content-Type":"application/json"},
  body:JSON.stringify({product_id:id})
 }).then(()=>location.reload());
}

function toBase64(file){
 return new Promise((res,rej)=>{
  const r=new FileReader();
  r.onload=()=>res(r.result);
  r.onerror=e=>rej(e);
  r.readAsDataURL(file);
 });
}

</script>

</body>
</html>`;

return [{json:{html}}];

