// ✅ دالة لتنظيف روابط الصور من \n
const cleanUrl = (url) => {
  if (!url) return "";
  return url.replace(/[\n\r\s]+/g, '').trim();
};

console.log("Update request:", body);

const images = [];

if (body.images && Array.isArray(body.images) && body.images.length > 0) {
  // صور جديدة
  body.images.forEach((img, index) => {
    if (img.base64 && img.base64.startsWith('data:image')) {
      images.push({
        fileName: img.name || `image${index + 1}.jpg`,
        mimeType: img.mimeType || "image/jpeg",
        base64: img.base64
      });
    } else if (img.fileName && img.fileName.startsWith('http')) {
      images.push({
        fileName: cleanUrl(img.fileName),  // ✅ تنظيف
        mimeType: "image/png",
        base64: null
      });
    }
  });
} else {
  // ✅ احتفظ بالصور القديمة (منظّفة)
  for (let i = 1; i <= 4; i++) {
    const existingUrl = cleanUrl(existingProduct[`image_url_${i}`]);
    if (existingUrl && existingUrl.startsWith('http')) {
      images.push({
        fileName: existingUrl,
        mimeType: "image/png",
        base64: null
      });
    }
  }
}

return [{
  json: {
    product_id: body.product_id,
    name: body.name,
    description: body.description,
    price: body.price,
    image_url_1: cleanUrl(existingProduct.image_url_1),  // ✅ تنظيف
