const body = $node["Messenger Webhook1"].json.body;
const objectType = body.object;
const entry = body.entry[0];
let senderId, messageText, pageId, timestamp;

if (entry.changes) {
  const change = entry.changes[0].value;
  senderId = change.sender?.id || change.from?.id;
  messageText = change.message?.text || change.messages?.[0]?.text;
  pageId = change.recipient?.id || entry.id;
  timestamp = change.timestamp || Date.now();
} else {
  const messaging = entry.messaging[0];
  const msgSender = messaging.sender.id;
  const msgRecipient = messaging.recipient?.id;
  pageId = entry.id; // ✅ دائماً page_id صحيح

  // ✅ للإنستغرام: sender قد يكون الصفحة نفسها، نأخذ الطرف الآخر
  if (objectType === 'instagram' && msgSender === pageId) {
    senderId = msgRecipient;
  } else {
    senderId = msgSender;
  }

  messageText = messaging.message?.text;
  timestamp = messaging.timestamp;
}

if (!messageText) throw new Error("No message text");

return [{
  json: { input: messageText, senderId, pageId, timestamp, source: objectType }
}];

