}

return [{
  json: {
    valid: true,
    order_timestamp: String(body.order_id),  // ✅ keep as string timestamp
    user_id: String(body.user_id),
    confirmed_at: new Date().toISOString()
  }
}];

const order = $input.first().json;

// ✅ Check if order was actually found
if (!order || !order.id) {
  return [{
    json: {
      authorized: false,
      error: 'Order not found'
    }
  }];
}

const requestUserId = String($('Validate Data1').first().json.user_id);
const orderUserId = String(order.user_id);

if (orderUserId !== requestUserId) {
  return [{
    json: {
      authorized: false,
      error: 'Unauthorized: Order belongs to different user'
    }
  }];
}

return [{
  json: {
    authorized: true,
    order: order
  }
}];

const order = $('User Authorization Check1').first().json.order;

return [{
  json: {
    success: true,
    message: 'تم تثبيت الحجز بنجاح',
    order_id: order.id,
    order_details: {
      product: order.selectedProduct,
      phone: order.phone,
      address: order.address,
      status: 'confirmed',
      confirmed_at: $('Validate Data1').first().json.confirmed_at
    }
  }
}];

return [{
  json: {
    success: false,
    error: 'الطلب غير موجود',
    message: 'لم يتم العثور على الطلب المطلوب'
  }
}];

const targetTimestamp = $('Validate Data1').first().json.order_timestamp;
const orders = $input.all();

const matched = orders.find(item => 
  item.json.timestamp && item.json.timestamp.startsWith(targetTimestamp)
);

if (!matched) {
  return [{ json: { id: null } }];
}

return [{ json: matched.json }];

const user = $json;
const status = user.status || 'approved';

if (status === 'pending') {
  throw new Error('حسابك قيد المراجعة. انتظر الموافقة.');
}

return [{json: user}];

const { email, password, name, store_name, phone } = $json.body;

// التحقق من الحقول المطلوبة
if (!email || !password || !name || !store_name || !phone) {
  throw new Error('جميع الحقول مطلوبة');
}

// التحقق من البريد
if (!email.includes('@')) {
  throw new Error('البريد الإلكتروني غير صحيح');
}

// التحقق من كلمة المرور
if (password.length < 6) {
  throw new Error('كلمة المرور قصيرة جداً');
}

return [{
  json: {
    email: email.toLowerCase().trim(),
    password: password,
    name: name.trim(),
    store_name: store_name.trim(),
    phone: phone.trim()
  }
}];

const validatedData = $input.first().json;
const checkResults = $('Check Email Exists').all();

// فحص إذا النتيجة تحتوي على email
const emailExists = checkResults.length > 0 && 
                    checkResults[0].json.email !== undefined;

return [{
  json: {
    ...validatedData,
    emailExists
  }
}];

const items = $input.all();
// إذا لا يوجد سياق للمستخدم → أرجع قيمة افتراضية للاستمرار
if (items.length === 0) {
  return [{ json: { selectedProduct: null, senderId: null, _noContext: true } }];
}
return items;

