const chatItems = $('Fetch Chat Requests').all();
const fbPages = $('Get FB Pages For Chat').all();
const customerInfo = $input.all();

// page_id → access_token
const pageTokenMap = {};
fbPages.forEach(p => {
  const pid = p.json.page_id?.toString().trim();
  if (pid && p.json.access_token) pageTokenMap[pid] = p.json.access_token;
});

// senderId → name (from Graph API node)
const nameMap = {};
customerInfo.forEach(c => {
  if (c.json.id && c.json.name) nameMap[c.json.id] = c.json.name;
});

const requests = chatItems.map(item => {
  const senderId = item.json.senderId;
  const pageId = item.json.page_id?.toString().trim();
  const customerName = nameMap[senderId] || ('...' + (senderId ? senderId.slice(-6) : 'زبون'));

  return {
    id: item.json.id,
    senderId,
    page_id: pageId,
    customerName,
    requestedAt: item.json.updatedAt,
    status: 'waiting',
    messengerLink: `https://www.facebook.com/messages/t/${senderId}`
  };
});

return [{ json: { success: true, count: requests.length, chat_requests: requests } }];
